.flex-container {
  display: flex;
  gap: 1rem;
  flex-wrap: wrap;
  justify-content: space-between;
  align-items: center;
}

.flex-item {
  flex: 1 1 200px; /* grow shrink basis */
}

/* 縦並び */
.flex-column {
  display: flex;
  flex-direction: column;
  gap: 0.5rem;
}

.grid-layout {
  display: grid;
  grid-template-columns: repeat(3, 1fr);
  grid-template-rows: auto 1fr auto;
  gap: 1rem;
  min-height: 100vh;
}

.header { grid-column: 1 / -1; }
.main   { grid-column: 1 / 3; }
.aside  { grid-column: 3; }
.footer { grid-column: 1 / -1; }

/* レスポンシブカードグリッド */
.card-grid {
  display: grid;
  grid-template-columns: repeat(
    auto-fill, minmax(250px, 1fr)
  );
  gap: 1rem;
}

.layout {
  display: grid;
  grid-template-areas:
    "header header  header"
    "main   main    sidebar"
    "footer footer  footer";
  grid-template-columns: 1fr 1fr 200px;
  grid-template-rows: auto 1fr auto;
  min-height: 100vh;
}

.header  { grid-area: header; }
.main    { grid-area: main; }
.sidebar { grid-area: sidebar; }
.footer  { grid-area: footer; }

@media (max-width: 768px) {
  .layout {
    grid-template-areas:
      "header"
      "main"
      "sidebar"
      "footer";
    grid-template-columns: 1fr;
  }
}

/* 相対位置（自身の元の位置から移動） */
.relative { position: relative; top: 10px; }

/* 絶対位置（最寄りの positioned 祖先基準） */
.parent { position: relative; }
.child  { position: absolute; top: 0; right: 0; }

/* 固定位置（ビューポート基準） */
.fixed-header {
  position: fixed;
  top: 0; left: 0; right: 0;
  z-index: 100;
}

/* スティッキー（スクロール追従） */
.sticky-nav {
  position: sticky;
  top: 0;
}

/* ブロック要素 */
.block { display: block; }

/* インライン要素 */
.inline { display: inline; }

/* インラインブロック（幅・高さ指定可） */
.inline-block { display: inline-block; }

/* 非表示（DOMから消去） */
.hidden { display: none; }

/* Flexbox / Grid */
.flex { display: flex; }
.grid { display: grid; }

/* 要素自体を消しつつ子を維持 */
.contents { display: contents; }

/* はみ出しを隠す */
.clip { overflow: hidden; }

/* 必要時のみスクロール */
.scroll { overflow: auto; }

/* 横スクロールのみ */
.scroll-x {
  overflow-x: auto;
  overflow-y: hidden;
  white-space: nowrap;
}

/* テキスト省略 */
.truncate {
  overflow: hidden;
  text-overflow: ellipsis;
  white-space: nowrap;
}

/* Flexbox（最も汎用的） */
.center-flex {
  display: flex;
  justify-content: center;
  align-items: center;
}

/* Grid（最短） */
.center-grid {
  display: grid;
  place-items: center;
}

/* margin auto（水平のみ、幅必須） */
.center-margin {
  width: fit-content;
  margin-inline: auto;
}

/* 絶対配置 + transform */
.center-absolute {
  position: absolute;
  top: 50%;
  left: 50%;
  transform: translate(-50%, -50%);
}
